using BotFramework.Discord.Commands;using BotFramework.Discord.Routing;using Games.SecretHitler.Application.Services;using Games.SecretHitler.Domain.Results;
namespace Games.SecretHitler.Discord;
public sealed class SecretHitlerDiscordHandler(ISecretHitlerService service):IDiscordMessageHandler{public bool CanHandle(DiscordMessageContext c)=>DiscordCommand.Is(c,"sh","secrethitler");public async Task HandleAsync(DiscordMessageContext c){var p=DiscordCommand.Parts(c);var uid=DiscordCommand.UserId(c);object? r;if(p.Length<2){var x=await service.FindMyGameAsync(uid,c.CancellationToken);r=x.Snapshot;}else switch(p[1].ToLowerInvariant()){case "create":r=await service.CreateGameAsync(uid,DiscordCommand.DisplayName(c),DiscordCommand.ScopeId(c),DiscordCommand.ScopeId(c),c.CancellationToken);break;case "join" when p.Length>2:r=await service.JoinGameAsync(uid,DiscordCommand.DisplayName(c),DiscordCommand.ScopeId(c),p[2],c.CancellationToken);break;case "start":r=await service.StartGameAsync(uid,c.CancellationToken);break;case "nominate" when p.Length>2&&int.TryParse(p[2],out var pos):r=await service.NominateAsync(uid,pos,c.CancellationToken);break;case "vote" when p.Length>2:r=await service.VoteAsync(uid,p[2].Equals("ja",StringComparison.OrdinalIgnoreCase)?ShVote.Ja:ShVote.Nein,c.CancellationToken);break;case "discard" when p.Length>2&&int.TryParse(p[2],out var di):r=await service.PresidentDiscardAsync(uid,di,c.CancellationToken);break;case "enact" when p.Length>2&&int.TryParse(p[2],out var ei):r=await service.ChancellorEnactAsync(uid,ei,c.CancellationToken);break;case "leave":r=await service.LeaveAsync(uid,c.CancellationToken);break;case "state":var x=await service.FindMyGameAsync(uid,c.CancellationToken);r=x.Snapshot;break;default:await DiscordCommand.ReplyAsync(c,"`sh create|join <code>|start|state|nominate <pos>|vote ja|nein|discard <idx>|enact <idx>|leave`");return;}await DiscordCommand.ReplyResultAsync(c,r,"Secret Hitler");}}
public static class SecretHitlerDiscordModule{public static IServiceCollection AddSecretHitlerDiscord(this IServiceCollection s)=>s.AddScoped<IDiscordMessageHandler,SecretHitlerDiscordHandler>();}
